import React, { useEffect, useRef, useState } from "https://cdn.skypack.dev/react";
import ReactDOM from "https://cdn.skypack.dev/react-dom";
import {
  Container,
  TextField,
  Typography,
  Box,
  Button,
  MenuItem,
  Paper,
  InputAdornment,
  ClickAwayListener,
} from "https://cdn.skypack.dev/@material-ui/core";

// ─── helpers ─────────────────────────────────────────────────────────────────

const createRow = () => ({
  id: Date.now() + Math.random(),
  dataset: "",
  sheet: "",
  start_cell: "",
});

// ─── shared logic ─────────────────────────────────────────────────────────────

// update rows + sync ToolJet
const updateRows = (data, rows, updateData) => {
  updateData({ ...data, rows });
};

// ─── SearchableSelect ─────────────────────────────────────────────────────────

const SearchableSelect = ({ value, datasets, onChange }) => {
  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState("");
  const anchorRef = useRef(null);

  const filtered = datasets.filter((d) =>
    d.dataset.toLowerCase().includes(search.toLowerCase())
  );

  const handleSelect = (d) => {
    onChange(d.dataset);
    setSearch("");
    setOpen(false);
  };

  return (
    <ClickAwayListener onClickAway={() => setOpen(false)}>
      <Box style={{ position: "relative" }} ref={anchorRef}>
        <TextField
          size="small"
          variant="outlined"
          fullWidth
          placeholder="Select dataset..."
          value={open ? search : value || ""}
          onChange={(e) => {
            setSearch(e.target.value);
            if (!open) setOpen(true);
          }}
          onFocus={() => setOpen(true)}
          inputProps={{ style: { cursor: "pointer" } }}
          InputProps={{
            endAdornment: (
              <InputAdornment position="end">
                <span style={{ fontSize: 10, color: "#aaa" }}>
                  {open ? "▲" : "▼"}
                </span>
              </InputAdornment>
            ),
          }}
        />

        {open && (
          <Paper
            elevation={4}
            style={{
              position: "absolute",
              top: "calc(100% + 4px)",
              left: 0,
              right: 0,
              zIndex: 1300,
              maxHeight: 220,
              overflowY: "auto",
            }}
          >
            {filtered.length > 0 ? (
              filtered.map((d) => (
                <MenuItem
                  key={d.dataset}
                  selected={d.dataset === value}
                  onClick={() => handleSelect(d)}
                  style={{ fontSize: 13 }}
                >
                  {d.dataset}
                </MenuItem>
              ))
            ) : (
              <MenuItem disabled>No results</MenuItem>
            )}
          </Paper>
        )}
      </Box>
    </ClickAwayListener>
  );
};

// ─── DatasetRow ───────────────────────────────────────────────────────────────

const DatasetRow = ({ row, datasets, onChange, onRemove }) => (
  <Box
    display="grid"
    gridTemplateColumns="2fr 1fr 1fr auto"
    alignItems="center"
    style={{ gap: 8, padding: "8px 0", borderBottom: "1px solid #f0f0f0" }}
  >
    <SearchableSelect
      value={row.dataset}
      datasets={datasets}
      onChange={(val) => onChange(row.id, "dataset", val)}
    />

    <TextField
      size="small"
      variant="outlined"
      placeholder="Sheet name"
      value={row.sheet}
      onChange={(e) => onChange(row.id, "sheet", e.target.value)}
    />

    <TextField
      size="small"
      variant="outlined"
      placeholder="e.g. A1"
      value={row.start_cell}
      onChange={(e) => onChange(row.id, "start_cell", e.target.value)}
    />

    <Button
      size="small"
      variant="outlined"
      color="secondary"
      onClick={() => onRemove(row.id)}
      style={{ whiteSpace: "nowrap", height: 40 }}
    >
      Remove
    </Button>
  </Box>
);

// ─── Main Component ───────────────────────────────────────────────────────────

const MyCustomComponent = ({ data, updateData }) => {
  const datasets = Array.isArray(data?.datasets) ? data.datasets : [];
  const rows = Array.isArray(data?.rows) ? data.rows : [];

  // init row
  useEffect(() => {
    if (!rows.length) {
      updateRows(data, [createRow()], updateData);
    }
  }, []);

  // xử lý change field
  const handleChange = (id, field, value) => {
    const newRows = rows.map((r) =>
      r.id === id ? { ...r, [field]: value } : r
    );
    updateRows(data, newRows, updateData);
  };

  const handleAdd = () => {
    updateRows(data, [...rows, createRow()], updateData);
  };

  const handleRemove = (id) => {
    const updated = rows.filter((r) => r.id !== id);
    updateRows(data, updated.length ? updated : [createRow()], updateData);
  };

  return (
    <Container maxWidth={false} style={{ padding: 16 }}>
      <Box mb={1}>
        <Typography variant="subtitle1" style={{ fontWeight: 600 }}>
          Dataset Mapping
        </Typography>

        <Typography
          variant="body2"
          style={{ fontSize: 13, color: "#6b7280", marginTop: 2 }}
        >
          Map each dataset to an Excel sheet and define where the data will start.
        </Typography>
      </Box>

      {/* header */}
      <Box
        display="grid"
        gridTemplateColumns="2fr 1fr 1fr auto"
        style={{
          gap: 8,
          padding: "4px 0 8px",
          borderBottom: "2px solid #e0e0e0",
          fontSize: 13,
          fontWeight: 600,
          color: "#555",
        }}
      >
        <div>Dataset</div>
        <div>Sheet</div>
        <div>Start Cell</div>
        <div style={{ width: 80 }} />
      </Box>

      {/* rows */}
      {rows.map((row) => (
        <DatasetRow
          key={row.id}
          row={row}
          datasets={datasets}
          onChange={handleChange}
          onRemove={handleRemove}
        />
      ))}

      {/* add button */}
      <Box mt={2}>
        <Button size="small" color="primary" onClick={handleAdd}>
          + Add Dataset
        </Button>
      </Box>
    </Container>
  );
};

// ─── Bootstrap ────────────────────────────────────────────────────────────────

const ConnectedComponent = Tooljet.connectComponent(MyCustomComponent);
ReactDOM.render(<ConnectedComponent />, document.body);

