import React from 'https://cdn.skypack.dev/react';
import ReactDOM from 'https://cdn.skypack.dev/react-dom';

const MyCustomComponent = ({ data, updateData }) => {
  const {
    values = [12, 19, 8, 24, 17, 21, 14],
    label = 'Tần suất nhập liệu',
  } = data;

  // Tự tính 7 ngày: hôm nay - 6 đến hôm nay
  const getDayLabels = () => {
    const dayNames = ['CN', 'T2', 'T3', 'T4', 'T5', 'T6', 'T7'];
    const today = new Date();
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date(today);
      d.setDate(today.getDate() - (6 - i));
      return dayNames[d.getDay()];
    });
  };

  const days = getDayLabels();
  const max = Math.max(...values);
  const min = Math.min(...values);
  const total = values.reduce((a, b) => a + b, 0);
  const avg = Math.round(total / values.length);

  const W = 600, H = 120;
  const PAD_LEFT = 36, PAD_RIGHT = 12, PAD_TOP = 12, PAD_BOT = 20;
  const chartW = W - PAD_LEFT - PAD_RIGHT;
  const chartH = H - PAD_TOP - PAD_BOT;

  const points = values.map((v, i) => {
    const x = PAD_LEFT + (i / (values.length - 1)) * chartW;
    const y = PAD_TOP + (1 - (v - min) / (max - min || 1)) * chartH;
    return { x, y, v };
  });

  const linePath = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
  const areaPath = `${linePath} L ${points[points.length-1].x} ${PAD_TOP + chartH} L ${points[0].x} ${PAD_TOP + chartH} Z`;

  const yTicks = [0, 0.33, 0.66, 1].map(t => ({
    y: PAD_TOP + (1 - t) * chartH,
    val: Math.round(min + t * (max - min)),
  }));

  const styles = {
    wrapper: {
      width: '100%', height: '100vh', margin: 0, padding: '28px 32px',
      display: 'flex', flexDirection: 'column', justifyContent: 'space-between',
      fontFamily: "'DM Sans', sans-serif", boxSizing: 'border-box',
    },
    header: { display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between' },
    label: { fontSize: '12px', fontWeight: 500, color: '#8a8780', textTransform: 'uppercase', letterSpacing: '0.06em' },
    totalNumber: { fontSize: 'clamp(32px, 5vw, 48px)', fontWeight: 700, letterSpacing: '-0.05em', lineHeight: 1, fontFamily: 'monospace', color: '#1a1916', textAlign: 'right' },
    totalSub: { fontSize: '11px', color: '#8a8780', marginTop: '2px', textAlign: 'right' },
    chartBox: { flex: 1, display: 'flex', alignItems: 'center', padding: '8px 0' },
    svg: { width: '100%', height: '100%', overflow: 'visible' },
    footer: { display: 'flex', alignItems: 'center', justifyContent: 'space-between' },
    footerItem: { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '2px' },
    footerVal: { fontSize: '13px', fontWeight: 600, fontFamily: 'monospace', color: '#1a1916' },
    footerKey: { fontSize: '10px', color: '#8a8780', textTransform: 'uppercase', letterSpacing: '0.05em' },
    divider: { width: '1px', height: '28px', background: '#e4e2dc' },
  };

  return (
    <div style={styles.wrapper}>

      <div style={styles.header}>
        <span style={styles.label}>{label}</span>
        <div>
          <div style={styles.totalNumber}>{total}</div>
          <div style={styles.totalSub}>lượt / 7 ngày</div>
        </div>
      </div>

      <div style={styles.chartBox}>
        <svg viewBox={`0 0 ${W} ${H}`} style={styles.svg} preserveAspectRatio="none">

          {/* Y axis */}
          <line x1={PAD_LEFT} y1={PAD_TOP} x2={PAD_LEFT} y2={PAD_TOP + chartH} stroke="#d0cdc8" strokeWidth="1" />

          {/* Y ticks + grid + labels */}
          {yTicks.map((t, i) => (
            <g key={i}>
              <line x1={PAD_LEFT - 4} y1={t.y} x2={PAD_LEFT} y2={t.y} stroke="#d0cdc8" strokeWidth="1" />
              <line x1={PAD_LEFT} y1={t.y} x2={W - PAD_RIGHT} y2={t.y} stroke="#f0ede8" strokeWidth="1" strokeDasharray="4 3" />
              <text x={PAD_LEFT - 6} y={t.y + 4} textAnchor="end" fontSize="9" fill="#8a8780" fontFamily="monospace">{t.val}</text>
            </g>
          ))}

          {/* Area fill */}
          <path d={areaPath} fill="rgba(42,92,255,0.06)" />

          {/* Line */}
          <path d={linePath} fill="none" stroke="#2a5cff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />

          {/* Dots + X labels */}
          {points.map((p, i) => (
            <g key={i}>
              <circle cx={p.x} cy={p.y} r="7" fill="rgba(42,92,255,0.12)" />
              <circle cx={p.x} cy={p.y} r="4" fill="#2a5cff" />
              <text
                x={p.x} y={H - 2}
                textAnchor="middle" fontSize="10" fontFamily="monospace"
                fill={i === 6 ? '#2a5cff' : '#8a8780'}
                fontWeight={i === 6 ? '600' : '400'}
              >
                {days[i]}
              </text>
            </g>
          ))}

        </svg>
      </div>

      <div style={styles.footer}>
        <div style={styles.footerItem}>
          <span style={styles.footerVal}>{avg}</span>
          <span style={styles.footerKey}>Trung bình</span>
        </div>
        <div style={styles.divider} />
        <div style={styles.footerItem}>
          <span style={{...styles.footerVal, color: '#2abf7a'}}>{max}</span>
          <span style={styles.footerKey}>Cao nhất</span>
        </div>
        <div style={styles.divider} />
        <div style={styles.footerItem}>
          <span style={{...styles.footerVal, color: '#ff5c2a'}}>{min}</span>
          <span style={styles.footerKey}>Thấp nhất</span>
        </div>
      </div>

    </div>
  );
};

