const EmailComposer = ({ data = {}, updateData }) => {
  const [preview, setPreview] = useState(false);
  const [subject, setSubject] = useState(data.subject || "");
  const [body, setBody] = useState(data.body || "");
  const [renderedSubject, setRenderedSubject] = useState("");
  const [renderedBody, setRenderedBody] = useState("");

  const handleSubjectChange = (value) => {
    setSubject(value);
    updateData({ ...data, subject: value, body });
  };

  const handleBodyChange = (value) => {
    setBody(value);
    updateData({ ...data, subject, body: value });
  };

  const renderTemplate = (text) => {
    if (!text) return "";
    return text.replace(/\{\{(.*?)\}\}/g, (match, key) => {
      const value = data[key.trim()];
      return value !== undefined ? value : match;
    });
  };

  const handlePreview = () => {
    if (!preview) {
      setRenderedSubject(renderTemplate(subject));
      setRenderedBody(renderTemplate(body));
    }
    setPreview(!preview);
  };

  const variables = Object.keys(data).filter(
    (k) => k !== "subject" && k !== "body"
  );

  return (
    <Container
      maxWidth={false}
      style={{
        padding: 20,
        width: "100%",
        height: "100vh",
        maxWidth: "100%",
