const schema_selected = components.dropdown_schema.selectedOption.value;

if (!catalog_selected || !schema_selected) {
    throw new Error("Catalog or schema is missing");
}

return `
SELECT table_name
FROM ${catalog_selected}.information_schema.tables
WHERE table_schema = '${schema_selected}'
  AND table_type = 'BASE TABLE';
`;

const sql = components.textarea_sql_script.value;

// Regex mới: \w cho phép chữ, số và dấu gạch dưới _
// Thêm \s* để bỏ qua khoảng trắng dư thừa nếu người dùng viết {{ from_dttm }}
const regex = /\{\{\s*(\w+)\s*\}\}/g;
const filters = [];
const seen = new Set();
let match;
let index = 1;

while ((match = regex.exec(sql)) !== null) {
  const paramName = match[1]; // Lấy group 1 (tên biến)

  if (seen.has(paramName)) continue;
  seen.add(paramName);

  filters.push({
    id: index++,
    name: paramName,
    // Logic tự động đoán type dựa trên tên biến
    type: paramName.includes('dttm') || paramName.includes('date') ? "datetime" : "varchar",
    min: "",
    max: "",
    regex: "",
    default_value:""
  });
}

return filters;

