function isReadOnlySelect(input) {
  if (typeof input !== 'string') return false;

  const s = input.trim();
  if (!s) return false;

  // Chặn comment SQL
  if (/--|\/\*|\*\//.test(s)) return false;

  // Chỉ cho 1 statement; cho phép 1 dấu ; ở cuối
  const withoutTrailingSemicolon = s.replace(/;\s*$/, '');
  if (withoutTrailingSemicolon.includes(';')) return false;

  // Phải bắt đầu bằng SELECT hoặc WITH
  if (!/^(select|with)\b/i.test(s)) return false;

  // Chặn lệnh ghi / sửa schema / quyền / thực thi
  const bannedKeywords = [
    'insert', 'update', 'delete', 'merge',
    'drop', 'alter', 'truncate', 'rename',
    'create', 'replace',
    'grant', 'revoke',
    'exec', 'execute', 'call', 'do',
    'copy', 'load', 'unload',
    'attach', 'detach',
    'use', 'set'
  ];

  const bannedRegex = new RegExp(`\\b(${bannedKeywords.join('|')})\\b`, 'i');
  if (bannedRegex.test(s)) return false;

  // Chặn pattern nguy hiểm dù là SELECT/WITH
  const bannedPatterns = [
    /\binto\s+(outfile|dumpfile)\b/i,
    /\binto\s+(temporary|temp)\b/i,
    /\bselect\b[\s\S]*\binto\b/i,
    /\bxp_cmdshell\b/i,
    /\bpg_sleep\s*\(/i,
    /\bbenchmark\s*\(/i,
    /\bsleep\s*\(/i
  ];

  if (bannedPatterns.some((re) => re.test(s))) return false;

  return true;
}

return isReadOnlySelect(sql);

